const item = $input.first();
const from = item.json.From || '';
const subject = item.json.Subject || '';
const rawText = item.json.text || item.json.snippet || '';


// ① <br>等のブロック要素を改行に変換してからHTMLタグを除去
let text = rawText
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/?(p|div|td|tr|li|h[1-6])\b[^>]*>/gi, '\n')
  .replace(/<[^>]*>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\r\n/g, '\n')
  .replace(/\r/g, '\n')
  .replace(/[ \t]+/g, ' ')
  .trim();

// ② 既知フィールドラベルの前に改行を挿入（長い順に処理して誤マッチ防止）
const FIELD_LABELS = [
  'お問い合わせの返信方法',
  'お問い合わせが電話の場合の希望日時',
  '出張先が自宅以外の場合は記入',
  '運転をしていない期間',
  '使用する教習車',
  'マイカーの車種',
  '第一希望時間', '第二希望時間', '第三希望時間',
  '第一希望日',  '第二希望日',  '第三希望日',
  'お支払い方法',
  'メッセージ',
  '講習の目安',
  'ふりがな',
  'メールアドレス',
  '電話番号',
  '出張先',
  '住所',
  '性別',
  '名前',
  '項目'
];

FIELD_LABELS.forEach(label => {
  const esc = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  // 改行がない場合のみ前に改行を挿入
  text = text.replace(new RegExp('([^\n])(' + esc + '[：:])', 'g'), '$1\n$2');
});

// ③ フィールド抽出（行頭アンカーで確実にマッチ）
function extractField(src, fieldName) {
  const esc = fieldName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = src.match(new RegExp('^' + esc + '[：:][ ]?(.+?)\\s*$', 'm'));
  return m ? m[1].trim() : '';
}

// 各フィールドを抽出
const parsed = {
  item:          extractField(text, '項目'),
  name:          extractField(text, '名前'),
  furigana:      extractField(text, 'ふりがな'),
  email:         extractField(text, 'メールアドレス'),
  phone:         extractField(text, '電話番号'),
  gender:        extractField(text, '性別'),
  address:       extractField(text, '住所'),
  nodriving:     extractField(text, '運転をしていない期間'),
  lessonTarget:  extractField(text, '講習の目安'),
  car:           extractField(text, '使用する教習車'),
  mycar:         extractField(text, 'マイカーの車種'),
  location:      extractField(text, '出張先'),
  locationOther: extractField(text, '出張先が自宅以外の場合は記入'),
  date1:         extractField(text, '第一希望日'),
  time1:         extractField(text, '第一希望時間'),
  date2:         extractField(text, '第二希望日'),
  time2:         extractField(text, '第二希望時間'),
  date3:         extractField(text, '第三希望日'),
  time3:         extractField(text, '第三希望時間'),
  payment:       extractField(text, 'お支払い方法'),
  message:       ''
};

// メッセージは複数行対応
const msgMatch = text.match(/^メッセージ[：:]\s*([\s\S]+?)(?:\n[^\n：:]+[：:]|$)/m);
if (msgMatch) {
  parsed.message = msgMatch[1].trim();
}

const isInquiryOnly = parsed.item.includes('お問い合わせのみ');

return [{ json: { from, subject, rawBody: text, parsed, isInquiryOnly } }];

// カレンダーイベントを整形
const events = $input.all();
const emailData = $('メール内容を整形').first().json;
const p = emailData.parsed;

const formattedEvents = events.map(e => {
  const ev = e.json;
  const start = ev.start?.dateTime || ev.start?.date || '';
  const end = ev.end?.dateTime || ev.end?.date || '';
  const title = ev.summary || '(無題)';
  return { title, start, end };
});

// 今日の日付
const today = new Date();
const todayStr = today.toLocaleDateString('ja-JP', {
  year: 'numeric', month: 'long', day: 'numeric', weekday: 'long',
  timeZone: 'Asia/Tokyo'
});

// カレンダー予定の文字列化
const calendarSummary = formattedEvents.length > 0
  ? formattedEvents.map(e => {
      const s = new Date(e.start);
      const en = new Date(e.end);
      const dateStr = s.toLocaleDateString('ja-JP', {
        month: 'long', day: 'numeric', weekday: 'short',
        timeZone: 'Asia/Tokyo'
      });
      const startTime = s.toLocaleTimeString('ja-JP', {
        hour: '2-digit', minute: '2-digit',
        timeZone: 'Asia/Tokyo'
      });
      const endTime = en.toLocaleTimeString('ja-JP', {
        hour: '2-digit', minute: '2-digit',
        timeZone: 'Asia/Tokyo'
      });
      // 終日イベントの場合
      if (e.start.length === 10) {
        return `・${dateStr} 終日 ${e.title}`;
      }
      return `・${dateStr} ${startTime}〜${endTime} ${e.title}`;
    }).join('\n')
  : '（予定なし）';

// 申し込み内容のサマリー
const inquirySummary = `項目: ${p.item}
名前: ${p.name}（${p.furigana}）様
メールアドレス: ${p.email}
電話番号: ${p.phone}
運転していない期間: ${p.nodriving}
使用車両: ${p.car}${p.mycar ? '（' + p.mycar + '）' : ''}
出張先: ${p.location}${p.locationOther ? '（' + p.locationOther + '）' : ''}
第一希望: ${p.date1} ${p.time1}
第二希望: ${p.date2} ${p.time2}
第三希望: ${p.date3} ${p.time3}
支払い: ${p.payment}
メッセージ: ${p.message}`;

const lineOfficialUrl = $vars.LINE_OFFICIAL_URL || 'https://lin.ee/vwFCADj';

const prompt = `あなたは「うめきた大阪ペーパードライバースクール」の受付担当・大西です。
以下のお申し込みメールに対して、返信メールを作成してください。

【今日の日付】
${todayStr}

【お申し込み内容】
${inquirySummary}

【カレンダーの予約状況（今後60日分）】
${calendarSummary}

---
【返信メールの作成ルール】

1. 書き出しは「${p.name}様」で始めること
2. 次に「この度は当スクールにお問合せいただき、誠にありがとうございます。受付担当の大西と申します。」を入れること
3. カレンダーを確認し、第一〜第三希望日の空き状況を明記すること
   - 空いている日程: 「〇月〇日（曜日）〇時スタート可能です」
   - 埋まっている日程: 「第〇希望は予約いっぱいとなっております」
   - 空き枠が決まったら「本日〇時まで仮押さえさせていただきます」と明記すること（翌日17時が目安）
4. お客様のメッセージ内容・ご状況に応じて、適切なコースを提案すること
   - 駐車のみ希望 → 「駐車やり方学ぼう（2時限）」など
   - 走る練習も必要そう → 「最低でも10時限、または20時限コースをおすすめしております」
   - 迷っている場合 → 「お試し教習70分を受講いただき、現在の運転状況を見させていただき教習担当と相談することも可能です」
5. 「進めていく場合は、下記LINE公式アカウントにご登録ください。当日の詳細をお送りします。登録後、${p.name}様のお名前のみお送りいただけますでしょうか。」を入れること
6. 末尾にLINE公式アカウントのURLを記載すること: ${lineOfficialUrl}
7. 件名は「Re: [元の件名]」形式
8. 丁寧・簡潔・温かみのある文体にすること

出力形式:
件名: Re: [件名]

[返信本文]`;

return [
  {
    json: {
      prompt,
      emailFrom: emailData.from,
      emailSubject: emailData.subject,
      parsed: p,
      isInquiryOnly: emailData.isInquiryOnly,
      calendarEventCount: formattedEvents.length
    }
  }
];

const claudeResponse = $input.first().json;
const prevData = $('カレンダー情報 & プロンプト作成').first().json;
const p = prevData.parsed;

// Claudeの返信テキストを取得
const replyText = claudeResponse.content?.[0]?.text || '';

// 申し込み種別ラベル
const typeLabel = prevData.isInquiryOnly ? '📋 お問い合わせ' : '📝 申し込み';

const message = [
  `${typeLabel} 新着メール`,
  '',
  `【お客様情報】`,
  `名前: ${p.name}（${p.furigana}）様`,
  `項目: ${p.item}`,
  `希望日: ${p.date1} ${p.time1} / ${p.date2} ${p.time2} / ${p.date3} ${p.time3}`,
  '',
  `【Claudeが作成した返信案】`,
  `（カレンダー ${prevData.calendarEventCount}件の予定を確認済み）`,
  '',
  replyText,
  '',
  '---',
  'この返信内容でよろしいですか？',
  '✅ 承認して送信 / ✏️ 修正が必要'
].join('\n');

return [
  {
    json: {
      lineMessage: message,
      lineBody: JSON.stringify({
        to: "Ua463857c1c61e16c09cc660730e69aca",
        messages: [{ type: 'text', text: message.substring(0, 5000) }]
      }),
      emailFrom: prevData.emailFrom,
      emailSubject: prevData.emailSubject,
      replyDraft: replyText,
      customerName: p.name,
      customerEmail: p.email
    }
  }
];
